refbody.section:
The sample JCL procedure ELAXFCP1 is used when you start
the include preprocessor that is supplied with the  product.
This JCL procedure must be used as a template to create a JCL procedure
that starts your own custom preprocessor. ELAXFCP1 was copied to ELAXFCP9
and altered to call TMPLT00. 
//ELAXFCP9 PROC LNGPRFX='IGYV3R40',
//            CICSLOD='CICSVS.TS230.CICS',
//            DB2LOD='DSN.DSN7',
//            LODPRFX='FOWLERM'
//*
//PREPROC1 EXEC PGM=TMPLT00,REGION=0M,
//            PARM=('TRACE(ON)')
//STEPLIB  DD DISP=SHR,DSN=MEL.LOAD
//         DD DISP=SHR,DSN=&LODPRFX..I1.L1;
//SYSPPOUT DD DSN=&&TEMPFILE;,DISP=(MOD,PASS),
//        UNIT=SYSALLDA,SPACE=(1800,(2500,2500))
//*
//COBOL    EXEC PGM=IGYCRCTL,REGION=0M,
//            PARM=('EXIT(ADEXIT(ELAXMGUX))',
//            'ADATA',
//            'LIB',
//            'TEST(ALL,SYM,SEP)',
//            'LIST',
//            'FLAG(I,I)'&CICS;&DB2;&COMP;)
//STEPLIB  DD  DSNAME=FOWLERM.ERRFDBK8.FIDUCIA1.LOAD,
//             DISP=SHR
//         DD  DSNAME=&LNGPRFX..SIGYCOMP;,
//             DISP=SHR
//         DD DSNAME=&CICSLOD..SDFHLOAD;,
//             DISP=SHR
//         DD DSNAME=&DB2LOD..SDSNLOAD;,
//             DISP=SHR
//         DD DSNAME=&DB2LOD..SDSNEXIT;,
//             DISP=SHR
//SYSIN    DD DISP=(OLD,DELETE),DSN=&&TEMPFILE;
//SYSLIN   DD DUMMY
//SYSLIB   DD DUMMY
//SYSADATA DD DUMMY
//SYSPRINT DD SYSOUT=*
//SYSUT1   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//SYSUT2   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//SYSUT3   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//SYSUT4   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//SYSUT5   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//SYSUT6   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//SYSUT7   DD UNIT=SYSALLDA,SPACE=(CYL,(1,1))
//*
